/// 品牌图标形状：折线多边形，evenodd 填充（正确处理镂空，如 OpenAI 花瓣中心）。
struct BrandIconShape: Shape {
    let polys: [[CGPoint]]
    func path(in rect: CGRect) -> Path {
        let s = min(rect.width, rect.height)
        let ox = rect.minX + (rect.width - s) / 2
        let oy = rect.minY + (rect.height - s) / 2
        var p = Path()
        for poly in polys {
            guard let first = poly.first else { continue }
            p.move(to: CGPoint(x: ox + first.x * s, y: oy + first.y * s))
            for pt in poly.dropFirst() {
                p.addLine(to: CGPoint(x: ox + pt.x * s, y: oy + pt.y * s))
            }
            p.closeSubpath()
        }
        return p
    }
}

/// 品牌图标视图：像 SF Symbol 一样用 foregroundColor 染色、frame 定尺寸。
struct BrandIcon: View {
    let polys: [[CGPoint]]
    var body: some View {
        BrandIconShape(polys: polys).fill(style: FillStyle(eoFill: true))
    }
}
